import React from "react";

const ContenedorLateral = ({
  subtitulo,
  imagen,
  ovaloRedondez,
  cuadroRedondez,
  className = "", // Prop para clases adicionales
}) => {
  return (
    <div
      className={`relative flex flex-col items-center justify-start z-10 ml-auto bg-surface-elevated border-stroke border-solid ${className}`}
      style={{
        borderColor: "#072D42", // Color primary (azul marino) de la paleta
        borderWidth: "clamp(2px, 0.618vh, 4px)",
        borderRadius: `${cuadroRedondez} 0 0 ${cuadroRedondez}`,
        marginTop: "clamp(2rem, 6.18vh, 4rem)",
      }}
    >
      {/* Contenedor padre que incluye el óvalo y el contenido */}
      <div className="relative w-full h-full flex flex-col items-center justify-start">
        {/* Subtítulo en óvalo */}
        <div
          className="absolute bg-surface-elevated shadow-md flex items-center justify-center border-solid border-stroke text-black font-bold text-center leading-tight whitespace-nowrap overflow-hidden text-ellipsis
                     px-3 md:px-6 lg:px-8 py-2 md:py-3
                     font-bodoni"
          style={{
            letterSpacing: "clamp(0.05rem, 0.1rem, 0.15rem)", // Reducido para mejor ajuste
            fontSize: "clamp(0.75rem, 1vw, 1.25rem)", // Reducido para que entre mejor
            borderRadius: ovaloRedondez,
            left: "50%",
            top: "clamp(-10%, -8%, -5%)", // Ajustado para mejor posicionamiento
            transform: "translateX(-50%)",
            maxWidth: "clamp(250px, 45%, 350px)",
            width: "auto",
            minWidth: "clamp(220px, 40%, 300px)",
            height: "clamp(45px, 9vh, 65px)",
            borderColor: "#E5E7EB",
            borderWidth: "clamp(1px, 0.1618vh, 2px)",
          }}
        >
          {subtitulo}
        </div>

        {/* Contenido dentro del contenedor */}
        <div
          className="w-full text-sm text-center mt-[clamp(3.5rem,9vh,6rem)]"
        >
          {/* Contenedor de la imagen */}
          <div
            className="relative flex justify-center items-center overflow-hidden mx-auto
                       w-[clamp(200px,55%,380px)] h-[clamp(140px,35vh,280px)]
                       p-[clamp(1rem,2.5vw,2rem)]"
          style={{
            borderRadius: ovaloRedondez,
          }}
          >
            <img
              src={imagen}
              alt="contenido dinámico"
              className="block w-full h-full object-cover transition-transform duration-300 hover:scale-105"
              style={{
                borderRadius: ovaloRedondez,
              }}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default ContenedorLateral;
